const body = $input.first().json.body;

console.log('Received preference data:', JSON.stringify(body, null, 2));

if (!body.userId) {
  throw new Error('Missing userId');
}
if (!body.userEmail) {
  throw new Error('Missing userEmail');
}
if (!body.summaryPreference) {
  throw new Error('Missing summaryPreference');
}

const allowedPreferences = ['action_first', 'standard'];
if (!allowedPreferences.includes(body.summaryPreference)) {
  throw new Error(`Invalid summary preference: ${body.summaryPreference}`);
}

console.log(`✅ Valid preference data for ${body.userEmail}: ${body.summaryPreference}`);

return [{
  json: {
    userId: body.userId,
    userEmail: body.userEmail,
    userName: body.userName || '',
    summaryPreference: body.summaryPreference,
    preferencesSetAt: new Date().toISOString()
  }
}];
